const { spawn } = require('child_process');
const path = require('path');
const { URL } = require('url');

class SecureGitManager {
  constructor() {
    this.ALLOWED_PROTOCOLS = ['https:', 'ssh:'];
    this.BRANCH_PATTERN = /^[a-zA-Z0-9/_.-]{1,64}$/;
    this.WORKSPACE_DIR = '/var/app/workspace';
  }

  validateRepoUrl(repoUrl) {
    let url;
    try {
      url = new URL(repoUrl);
    } catch (error) {
      throw new Error('Invalid repository URL');
    }

    // Only allow HTTPS and SSH
    if (!this.ALLOWED_PROTOCOLS.includes(url.protocol)) {
      throw new Error(`Protocol not allowed: ${url.protocol}`);
    }

    // Validate hostname format
    if (!/^[a-zA-Z0-9.-]+$/.test(url.hostname)) {
      throw new Error('Invalid hostname');
    }

    return repoUrl;
  }

  validateBranch(branch) {
    if (!this.BRANCH_PATTERN.test(branch)) {
      throw new Error('Invalid branch name format');
    }
    return branch;
  }

  cloneRepository(repoUrl, branch) {
    return new Promise((resolve, reject) => {
      try {
        // Validate inputs
        const validUrl = this.validateRepoUrl(repoUrl);
        const validBranch = this.validateBranch(branch);

        const targetDir = path.join(this.WORKSPACE_DIR, `repo_${Date.now()}`);

        // Use spawn with argument array (no shell)
        const gitProcess = spawn('git', [
          'clone',
          '--depth', '1',
          '--branch', validBranch,
          '--single-branch',
          validUrl,
          targetDir
        ], {
          shell: false,  // CRITICAL: No shell execution
          timeout: 60000, // 60 second timeout
          env: {  // Minimal environment
            PATH: '/usr/bin:/bin',
            HOME: process.env.HOME
          }
        });

        let stdout = '';
        let stderr = '';

        gitProcess.stdout.on('data', (data) => {
          stdout += data.toString();
        });

        gitProcess.stderr.on('data', (data) => {
          stderr += data.toString();
        });

        gitProcess.on('close', (code) => {
          if (code === 0) {
            resolve({ success: true, directory: targetDir });
          } else {
            reject(new Error('Git clone failed'));
          }
        });

        gitProcess.on('error', (error) => {
          reject(new Error('Failed to execute git command'));
        });

      } catch (error) {
        reject(error);
      }
    });
  }
}

// Usage
