gitManager.cloneRepository('https://github.com/user/repo.git', 'main')
  .then(result => console.log('Success:', result))
  .catch(error => console.error('Error:', error.message));

// Attack blocked
gitManager.cloneRepository('https://github.com/user/repo.git', 'main; rm -rf /')
  .catch(error => console.error('Attack blocked:', error.message));
