class SecureGitOperations {
  constructor(repoPath) {
    this.repoPath = path.resolve(repoPath);
    this.COMMIT_MSG_PATTERN = /^[a-zA-Z0-9 .,!?'"()-]{1,500}$/;
  }

  executeGitCommand(args, timeout = 30000) {
    return new Promise((resolve, reject) => {
      const gitProcess = spawn('git', args, {
        cwd: this.repoPath,
        shell: false,
        timeout: timeout,
        env: { PATH: '/usr/bin:/bin' }
      });

      let stdout = '';
      let stderr = '';

      gitProcess.stdout.on('data', (data) => { stdout += data; });
      gitProcess.stderr.on('data', (data) => { stderr += data; });

      gitProcess.on('close', (code) => {
        if (code === 0) {
          resolve({ success: true, output: stdout });
        } else {
          reject(new Error('Git command failed'));
        }
      });
    });
  }

  async checkout(branch) {
    const validBranch = this.validateBranch(branch);
    return this.executeGitCommand(['checkout', validBranch]);
  }

  async pull(remote = 'origin', branch = 'main') {
    const validBranch = this.validateBranch(branch);
    return this.executeGitCommand(['pull', remote, validBranch]);
  }

  async commit(message, author) {
    if (!this.COMMIT_MSG_PATTERN.test(message)) {
      throw new Error('Invalid commit message');
    }
    return this.executeGitCommand(['commit', '-m', message]);
  }
}

